&\phantom{=}-\dfrac{24}{\blueD{\left(\dfrac{\pi}{2}\right)}^3}\cos\blueD{\left(\dfrac{\pi}{2}\right)}-\dfrac{12}{\blueD{\left(\dfrac{\pi}{2}\right)}^2}\sin\blueD{\left(\dfrac{\pi}{2}\right)}
\\\\
&=-\dfrac{192}{\pi^3}(0)-\dfrac{48}{\pi^2}(1)
\\\\
&=-\dfrac{48}{\pi^2}
\end{align}$

